.benchmark {
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-top: 3px solid #F59E0B;
  border-radius: 10px;
  padding: 1.75rem;
  margin-bottom: 2.5rem;
}

.benchmark:hover { border-color: #F59E0B; }

.benchmark-header { text-align: center; margin-bottom: 1.5rem; }

.benchmark-header h3 {
  font-size: 1.15rem;
  color: #F59E0B;
  margin-bottom: 0.25rem;
}

.benchmark-header p {
  font-size: 0.85rem;
  color: var(--text-secondary);
}

.benchmark-columns {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1.5rem;
  margin-bottom: 1.5rem;
}

.benchmark-col h4 {
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 1px;
  color: #F59E0B;
  margin-bottom: 0.75rem;
  padding-bottom: 0.4rem;
  border-bottom: 1px solid rgba(245, 158, 11, 0.2);
}

.benchmark-col ul {
  list-style: none;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.benchmark-col li {
  font-size: 0.82rem;
  color: var(--text-secondary);
  line-height: 1.5;
}

.benchmark-col li strong { color: var(--text-primary); font-weight: 600; }

.benchmark-steal {
  background: rgba(245, 158, 11, 0.06);
  border: 1px solid rgba(245, 158, 11, 0.15);
  border-radius: 8px;
  padding: 1.25rem;
}

.benchmark-steal h4 {
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 1px;
  color: #F59E0B;
  margin-bottom: 0.75rem;
}

.benchmark-steal ol {
  list-style: none;
  counter-reset: steal;
  display: flex;
  flex-direction: column;
  gap: 0.6rem;
}

.benchmark-steal li {
  counter-increment: steal;
  font-size: 0.82rem;
  color: var(--text-secondary);
  line-height: 1.5;
  padding-left: 1.75rem;
  position: relative;
}

.benchmark-steal li::before {
  content: counter(steal);
  position: absolute;
  left: 0;
  background: #F59E0B;
  color: #000;
  width: 20px; height: 20px;
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  font-weight: 700; font-size: 0.7rem;
  top: 0;
}

@media (max-width: 960px) {
  .benchmark-columns { grid-template-columns: 1fr; }
}

/* ---- Recommendations ---- */

